import play.api._
import play.api.mvc._
import scala.io.Source

class FileController extends Controller {
  def download(filename: String) = Action.async { request =>
    val filePath = s"uploads/$filename" // Prevent path traversal by using absolute paths instead of relative ones in the filename string
    
    Source.fromFile(filePath).getLines().map(line => 
      Results.download(contentTypeGetter(None, line), fileName => Some("attachment", s"""filename="${java.net.URLEncoder.encode(fileName,"UTF-8")}"""))  // Set the content type and filename for each downloaded part of a multipart request
    ).reduce(_ + _)   // Combine all parts into one response using reduce method, which is used to combine two responses in case when there are multiple files being sent. This will be useful if you have more than 1 file downloadable at once from the same path (e.g., a zip archive).
    }
}